{"type": "email", "id": "email_001", "subject": "Upcoming Marketing Team Meeting - Agenda Items", "from": "emily.chen@mediconnsolutions.com", "from_name": "Emily Chen", "to": ["david.king@mediconnsolutions.com"], "cc": ["linda.brown@mediconnsolutions.com"], "date": "2022-07-19 10:30:00", "body": "Hello David,

